Modify _sel_card (starmie_heuristics.py:437-448) and option_card_id (deck_policy_v3.py:216-222) to respect option.area:

```python
def _sel_card(sel, o):
    """Resolve a CARD option to its card id, respecting option.area."""
    idx = DP._get(o, "index", None)
    try:
        idx = int(idx)
    except Exception:
        return None

    # Map known area codes to sel zone keys
    area = DP._get(o, "area", None)
    area_to_key = {1: "deck", 2: "hand"}  # A_DECK=1, A_HAND=2

    # If area is known and mapped, check ONLY that zone
    if area is not None and area in area_to_key:
        zone = DP._items(DP._get(sel, area_to_key[area], []))
        if 0 <= idx < len(zone):
            return DP._cid(zone[idx])
        return None

    # Fallback for area=12 (reveal, context-dependent) or unknown areas
    for key in ("deck", "discard", "prize", "hand"):
        zone = DP._items(DP._get(sel, key, []))
        if 0 <= idx < len(zone):
            return DP._cid(zone[idx])
    return None
```

