Replace the blanket ABILITY suppression with a check of the ability's effect. Only suppress abilities that actually remove the Pokemon:

```python
def _no_suicide(obs):
    sel = DP._selection(obs)
    if not sel or int(DP._get(sel, "maxCount", 0) or 0) != 1:
        return None
    opts = DP._items(DP._get(sel, "option", []))
    me = _me_opp(obs)[0]
    in_play = (1 if DP._active(me) else 0) + len(DP._bench(me))
    if in_play > 1:
        return None

    # Check if there are abilities that actually remove the Pokemon
    ability_opts = [o for o in opts if o.get("type") == ABILITY]
    if not ability_opts:
        return None

    # Only suppress if abilities have self-removal effects
    for ability_opt in ability_opts:
        try:
            tgt = DP.option_target_entity(ability_opt, obs)
            if tgt:
                card_id = DP._cid(tgt)
                eff = CEFF.get(str(card_id), {}) if card_id else {}
                # Only suppress if ability has shuffle_hand or discard
                if eff.get("shuffle_hand") or eff.get("discard"):
                    end_idx = next((i for i, o in enumerate(opts) if o.get("type") == END), None)
                    if end_idx is not None:
                        return [end_idx]
        except Exception:
            pass

    return None
```

This preserves the original intent (prevent suicidal shuffle abilities) while allowing safe abilities (draw, search) to proceed.
